svg.script:
(function() {
  // 1. Берём трек
  const track = document.getElementById("ElipsTreck");
  const cx = parseFloat(track.getAttribute("cx"));
  const cy = parseFloat(track.getAttribute("cy"));
  const rx = parseFloat(track.getAttribute("rx"));
  const ry = parseFloat(track.getAttribute("ry"));

  // 2. Находим флаги
  const flags = [];
  for (let i = 1; i <= 10; i++) {
    const el = document.getElementById("ffffffffff" + i);
    if (el) flags.push(el);
  }

  // 3. Двигаем
  function animate(time) {
    flags.forEach((flag, i) => {
      const angle = (time * 0.0003) + (i / flags.length) * Math.PI * 2;
      const x = cx + rx * Math.cos(angle);
      const y = cy + ry * Math.sin(angle);
      flag.setAttribute("transform", "translate(" + x + "," + y + ")");
    });
    requestAnimationFrame(animate);
  }

  setTimeout(() => animate(0), 100);
})();
